__global__ void nw_optimized_kernel(int *input_itemsets, int *referrence, int max_rows, int max_cols, int penalty) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int idy = blockIdx.y * blockDim.y + threadIdx.y;

    if (idx < max_cols && idy < max_rows) {
        int b_index_x = idx / BLOCK_SIZE;
        int b_index_y = idy / BLOCK_SIZE;

        __shared__ int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
        __shared__ int reference_l[BLOCK_SIZE * BLOCK_SIZE];

        if (threadIdx.x < BLOCK_SIZE && threadIdx.y < BLOCK_SIZE) {
            reference_l[threadIdx.y * BLOCK_SIZE + threadIdx.x] = referrence[max_cols * (b_index_y * BLOCK_SIZE + threadIdx.y + 1) + b_index_x * BLOCK_SIZE + threadIdx.x + 1];
        }

        if (threadIdx.x < BLOCK_SIZE + 1 && threadIdx.y < BLOCK_SIZE + 1) {
            input_itemsets_l[threadIdx.y * (BLOCK_SIZE + 1) + threadIdx.x] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + threadIdx.y) + b_index_x * BLOCK_SIZE + threadIdx.x];
        }

        __syncthreads();

        if (threadIdx.x > 0 && threadIdx.x < BLOCK_SIZE + 1 && threadIdx.y > 0 && threadIdx.y < BLOCK_SIZE + 1) {
            input_itemsets_l[threadIdx.y * (BLOCK_SIZE + 1) + threadIdx.x] = maximum(input_itemsets_l[(threadIdx.y - 1) * (BLOCK_SIZE + 1) + threadIdx.x - 1] + reference_l[(threadIdx.y - 1) * BLOCK_SIZE + threadIdx.x - 1],
                    input_itemsets_l[threadIdx.y * (BLOCK_SIZE + 1) + threadIdx.x - 1] - penalty,
                    input_itemsets_l[(threadIdx.y - 1) * (BLOCK_SIZE + 1) + threadIdx.x] - penalty);
        }

        __syncthreads();

        if (threadIdx.x < BLOCK_SIZE && threadIdx.y < BLOCK_SIZE) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + threadIdx.y + 1) + b_index_x * BLOCK_SIZE + threadIdx.x + 1] = input_itemsets_l[(threadIdx.y + 1) * (BLOCK_SIZE + 1) + threadIdx.x + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence, int max_rows, int max_cols, int penalty) {
    int *d_input_itemsets, *d_referrence;
    cudaMalloc((void **)&d_input_itemsets, max_rows * max_cols * sizeof(int));
    cudaMalloc((void **)&d_referrence, max_rows * max_cols * sizeof(int));

    cudaMemcpy(d_input_itemsets, input_itemsets, max_rows * max_cols * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, max_rows * max_cols * sizeof(int), cudaMemcpyHostToDevice);

    dim3 blockSize(BLOCK_SIZE, BLOCK_SIZE);
    dim3 gridSize((max_cols + blockSize.x - 1) / blockSize.x, (max_rows + blockSize.y - 1) / blockSize.y);

    nw_optimized_kernel<<<gridSize, blockSize>>>(d_input_itemsets, d_referrence, max_rows, max_cols, penalty);

    cudaMemcpy(input_itemsets, d_input_itemsets, max_rows * max_cols * sizeof(int), cudaMemcpyDeviceToHost);

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

int main(int argc, char **argv) {
    int max_rows, max_cols, penalty;
    int *input_itemsets, *output_itemsets, *referrence;

    if (argc == 4) {
        max_rows = atoi(argv[1]);
        max_cols = atoi(argv[1]);
        penalty = atoi(argv[2]);
    } else {
        printf("Usage: %s <max_rows/max_cols> <penalty>\n", argv[0]);
        return 1;
    }

    max_rows = max_rows + 1;
    max_cols = max_cols + 1;
    referrence = (int *)malloc(max_rows * max_cols * sizeof(int));
    input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
    output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

    if (!input_itemsets) {
        printf("Error: cannot allocate memory\n");
        return 1;
    }

    for (int i = 0; i < max_cols; i++) {
        for (int j = 0; j < max_rows; j++) {
            input_itemsets[i * max_cols + j] = 0;
        }
    }

    printf("Start Needleman-Wunsch\n");

    for (int i = 1; i < max_rows; i++) {
        input_itemsets[i * max_cols] = rand() % 10 + 1;
    }
    for (int j = 1; j < max_cols; j++) {
        input_itemsets[j] = rand() % 10 + 1;
    }

    for (int i = 1; i < max_cols; i++) {
        for (int j = 1; j < max_rows; j++) {
            referrence[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
        }
    }

    for (int i = 1; i < max_rows; i++)
        input_itemsets[i * max_cols] = -i * penalty;
    for (int j = 1; j < max_cols; j++)
        input_itemsets[j] = -j * penalty;

    long long start_time = get_time();

    nw_optimized(input_itemsets, output_itemsets, referrence, max_rows, max_cols, penalty);

    long long end_time = get_time();

    printf("Total time: %.3f seconds\n", ((float)(end_time - start_time)) / (1000 * 1000));

    free(referrence);
    free(input_itemsets);
    free(output_itemsets);

    return 0;
}
